/**
 * Proof: sequence/rqa.js — RQA librosa fixture replay.
 *
 * Replays both cases of tools/parity/fixtures/rqa.json (generated by
 * librosa 0.11.0 `librosa.sequence.rqa`): the optimal alignment path must
 * agree ELEMENT-WISE ([n, m] pairs, exact) and max(score) must equal the
 * fixture's expected_score_max exactly. Plus one interpretable case: an 8×8
 * identity similarity matrix aligns along the full main diagonal
 * [[0,0]..[7,7]] with maxScore 8 (each diagonal cell adds sim 1).
 */
import { rqa } from '../../packages/pleco-xa/dist/pleco-xa.js'
import { check, checkTrue, summary } from './_harness.mjs'
import { readFileSync } from 'node:fs'
import { fileURLToPath } from 'node:url'

const fixture = JSON.parse(readFileSync(
  fileURLToPath(new URL('../../tools/parity/fixtures/rqa.json', import.meta.url)), 'utf8'))

const maxScore = (score) => {
  let mx = -Infinity
  for (const row of score) for (const v of row) if (v > mx) mx = v
  return mx
}

// ─── librosa fixture replay ─────────────────────────────────────────────────
for (const c of fixture.cases) {
  const { name, R, shape, gap_onset, gap_extend, knight_moves } = c.input
  const [N, M] = shape
  const sim = Array.from({ length: N }, (_, i) => R.slice(i * M, (i + 1) * M))

  const { score, path } = rqa(sim, {
    gapOnset: gap_onset,
    gapExtend: gap_extend,
    knightMoves: knight_moves,
  })

  checkTrue(
    `${name} (${N}×${M}): path exact element-wise match (${c.expected_path.length} pairs)`,
    JSON.stringify(path) === JSON.stringify(c.expected_path),
    `got ${path.length} pairs`,
  )
  check(`${name}: max(score) === ${c.expected_score_max}`, maxScore(score), c.expected_score_max)
}

// ─── interpretable case: 8×8 identity → full main diagonal ─────────────────
const I8 = Array.from({ length: 8 }, (_, i) =>
  Array.from({ length: 8 }, (_, j) => (i === j ? 1 : 0)))
const { score, path } = rqa(I8)
const diagonal = Array.from({ length: 8 }, (_, i) => [i, i])
check('identity 8×8: path is the full main diagonal [[0,0]..[7,7]]', path, diagonal)
check('identity 8×8: maxScore === 8', maxScore(score), 8)

summary('sequence/rqa.js — RQA librosa fixture replay')
